import os
import logging
import logging.handlers
import stat


def setup_logging():
    """Configure production logging with secure file handling and log rotation."""
    
    log_dir = '/var/log/application/'
    
    # Create log directory with restrictive permissions (owner read/write/execute only)
    if not os.path.exists(log_dir):
        os.makedirs(log_dir, mode=0o750)
    else:
        # Ensure existing directory has correct permissions
        os.chmod(log_dir, 0o750)
    
    # Define log file paths
    app_log_file = os.path.join(log_dir, 'app.log')
    error_log_file = os.path.join(log_dir, 'error.log')
    audit_log_file = os.path.join(log_dir, 'audit.log')
    
    # Secure formatter that avoids logging sensitive data
    detailed_formatter = logging.Formatter(
        fmt='%(asctime)s | %(levelname)-8s | %(name)s | %(module)s:%(funcName)s:%(lineno)d | %(message)s',
        datefmt='%Y-%m-%d %H:%M:%S'
    )
    
    error_formatter = logging.Formatter(
        fmt='%(asctime)s | %(levelname)-8s | %(name)s | %(pathname)s:%(lineno)d | %(message)s',
        datefmt='%Y-%m-%d %H:%M:%S'
    )
    
    audit_formatter = logging.Formatter(
        fmt='%(asctime)s | AUDIT | %(name)s | %(message)s',
        datefmt='%Y-%m-%d %H:%M:%S'
    )
    
    # Application log handler with rotation
    # Rotates at 50MB, keeps 10 backup files
    app_handler = logging.handlers.RotatingFileHandler(
        filename=app_log_file,
        maxBytes=50 * 1024 * 1024,  # 50 MB
        backupCount=10,
        encoding='utf-8'
    )
    app_handler.setLevel(logging.INFO)
    app_handler.setFormatter(detailed_formatter)
    
    # Error log handler with rotation
    error_handler = logging.handlers.RotatingFileHandler(
        filename=error_log_file,
        maxBytes=50 * 1024 * 1024,  # 50 MB
        backupCount=20,
        encoding='utf-8'
    )
    error_handler.setLevel(logging.ERROR)
    error_handler.setFormatter(error_formatter)
    
    # Audit log handler with time-based rotation (daily)
    audit_handler = logging.handlers.TimedRotatingFileHandler(
        filename=audit_log_file,
        when='midnight',
        interval=1,
        backupCount=90,  # Keep 90 days of audit logs
        encoding='utf-8',
        utc=True
    )
    audit_handler.setLevel(logging.INFO)
    audit_handler.setFormatter(audit_formatter)
    
    # Configure root logger
    root_logger = logging.getLogger()
    root_logger.setLevel(logging.INFO)
    root_logger.addHandler(app_handler)
    root_logger.addHandler(error_handler)
    
    # Configure audit logger separately
    audit_logger = logging.getLogger('audit')
