def _secure_log_file_permissions(filepath):
    """Set restrictive permissions on log files.
    
    Owner: read/write
    Group: read (for log aggregation tools)
    Others: no access
    """
    if os.path.exists(filepath):
        os.chmod(filepath, stat.S_IRUSR | stat.S_IWUSR | stat.S_IRGRP)  # 0o640


class SensitiveDataFilter(logging.Filter):
    """Filter to prevent sensitive data from being written to logs."""
    
    SENSITIVE_PATTERNS = [
        'password', 'passwd', 'secret', 'token', 'api_key', 'apikey',
        'authorization', 'credit_card', 'ssn', 'social_security'
    ]
    
    def filter(self, record):
        message = record.getMessage().lower()
        for pattern in self.SENSITIVE_PATTERNS:
            if pattern in message:
                record.msg = f"[REDACTED - message contained sensitive data pattern: '{pattern}']"
                record.args = None
                break
        return True


def get_logger(name):
    """Get a logger instance with the sensitive data filter applied."""
    logger = logging.getLogger(name)
    sensitive_filter = SensitiveDataFilter()
    logger.addFilter(sensitive_filter)
    return logger


def get_audit_logger():
    """Get the audit logger for recording audit events."""
    return logging.getLogger('audit')


